public class ArmstrongCheck {
    public static void main(String[] args) {
        int num = 153, temp = num, sum = 0;
        int digits = String.valueOf(num).length();
        while (temp > 0) {
            int d = temp % 10;
            sum += Math.pow(d, digits);
            temp /= 10;
        }
        System.out.println(num + " is Armstrong? " + (sum == num));
    }
}

